{"code": "import json, re
from collections import defaultdict

review_path = locals()['var_functions.query_db:8']
book_path = locals()['var_functions.query_db:10']

with open(review_path) as f:
    reviews = json.load(f)

with open(book_path) as f:
    books = json.load(f)

book_decades = {}
for b in books:
    m = re.search(r'(19\d{2}|20[0-2]\d)', b['details'])
    if m:
        year = int(m.group(1))
        book_decades[b['book_id']] = (year // 10) * 10

decade_stats = defaultdict(lambda: [0, 0, set()])  # sum, count, books

for r in reviews:
    m = re.search(r'(\d+)$', r['purchase_id'])
    if m:
        bid = 'bookid_' + m.group(1)
        if bid in book_decades:
            d = book_decades[bid]
            decade_stats[d][0] += float(r['rating'])
            decade_stats[d][1] += 1
            decade_stats[d][2].add(bid)

best = None
best_avg = 0

for d, (s, c, bks) in decade_stats.items():
    if len(bks) >= 10:
        avg = s / c
        if avg > best_avg:
            best_avg = avg
            best = d

print('__RESULT__:')
if best:
    print(str(best) + 's|' + str(round(best_avg, 3)) + '|' + str(len(decade_stats[best][2])) + '|' + str(decade_stats[best][1]))
else:
    print('none')
"}

